interface ConnectionTypeIconProps {
  /** Connection type (or 'AWS Last Mile'). Unknown types render nothing. */
  type: string;
  /** Rendered height in px; width derives from the icon's aspect ratio. */
  size?: number;
  /** Line weight in viewBox units; thickens every glyph's linework uniformly. */
  strokeWidth?: number;
  className?: string;
  /** Accessible label override; defaults to the type string. */
  title?: string;
  /** Surface color showing through the AWS twin-pin overlap mask. */
  haloColor?: string;
}

export function ConnectionTypeIcon({
  type,
  size = 24,
  strokeWidth = 1.5,
  className,
  title,
  haloColor = '#ffffff',
}: ConnectionTypeIconProps) {
  const factory = ICONS[type];
  if (!factory) return null;

  const { slug, vbW, vbH, paths } = factory(haloColor);
  // Several glyphs draw clouds right up to the viewBox edge; a uniform inset
  // gives every icon breathing room so nothing clips at the top or bottom.
  const PAD = 3;
  const boxW = vbW + PAD * 2;
  const boxH = vbH + PAD * 2;
  const width = Math.round((size * boxW) / boxH);

  return (
    <svg
      role="img"
      aria-label={title ?? type}
      data-icon={slug}
      width={width}
      height={size}
      viewBox={`${-PAD} ${-PAD} ${boxW} ${boxH}`}
      fill="none"
      stroke="currentColor"
      strokeWidth={strokeWidth}
      strokeLinejoin="round"
      strokeLinecap="round"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
    >
      {paths}
    </svg>
  );
}
